import{_ as t,o,c as r,ah as d}from"./chunks/framework.Bi9enVNS.js";const h=JSON.parse('{"title":"Normalization and Derivation","description":"","frontmatter":{},"headers":[],"relativePath":"en/reference/normalization.md","filePath":"en/reference/normalization.md","lastUpdated":1774205896000}'),a={name:"en/reference/normalization.md"};function i(c,e,n,s,l,u){return o(),r("div",null,[...e[0]||(e[0]=[d('<h1 id="normalization-and-derivation" tabindex="-1">Normalization and Derivation <a class="header-anchor" href="#normalization-and-derivation" aria-label="Permalink to &quot;Normalization and Derivation&quot;">​</a></h1><p>The query layer does not expose raw <code>LogRecord</code> values directly. The server first normalizes each accepted record into one unified shape and then derives timeline, topology, and source views from that data.</p><h2 id="normalizedlogrecord" tabindex="-1"><code>NormalizedLogRecord</code> <a class="header-anchor" href="#normalizedlogrecord" aria-label="Permalink to &quot;`NormalizedLogRecord`&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>Meaning</th></tr></thead><tbody><tr><td><code>log_id</code></td><td>Original log identifier</td></tr><tr><td><code>project</code></td><td>Logical project</td></tr><tr><td><code>environment</code></td><td>Logical environment</td></tr><tr><td><code>source_type</code></td><td>Source type without the <code>SOURCE_TYPE_</code> prefix, such as <code>SERVICE</code></td></tr><tr><td><code>source_name</code></td><td>Source name</td></tr><tr><td><code>source_id</code></td><td>Source identifier</td></tr><tr><td><code>instance_id</code></td><td>Instance identifier</td></tr><tr><td><code>timestamp</code></td><td><code>event_time</code>, converted to UTC</td></tr><tr><td><code>severity_number</code></td><td>Numeric severity</td></tr><tr><td><code>severity_text</code></td><td>Text severity</td></tr><tr><td><code>logger_name</code></td><td>Logger name</td></tr><tr><td><code>event_name</code></td><td>Event name</td></tr><tr><td><code>body_text</code></td><td>Search/display friendly text form</td></tr><tr><td><code>body_json</code></td><td>Raw JSON form of the body</td></tr><tr><td><code>attributes_json</code></td><td>Attributes as JSON</td></tr><tr><td><code>resource_json</code></td><td>Batch resource map as JSON</td></tr><tr><td><code>trace_id</code></td><td>Trace ID</td></tr><tr><td><code>span_id</code></td><td>Span ID</td></tr><tr><td><code>trace_flags</code></td><td>Trace flags</td></tr><tr><td><code>source_fingerprint</code></td><td>Source-instance aggregation key</td></tr></tbody></table><h2 id="source-fingerprint-formula" tabindex="-1"><code>source_fingerprint</code> formula <a class="header-anchor" href="#source-fingerprint-formula" aria-label="Permalink to &quot;`source_fingerprint` formula&quot;">​</a></h2><p>The current implementation uses:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sha256(project | environment | source_type | source_name | instance_id)</span></span></code></pre></div><p>It then keeps the first 16 bytes and encodes them as hexadecimal.</p><h2 id="effective-source-selection" tabindex="-1">Effective source selection <a class="header-anchor" href="#effective-source-selection" aria-label="Permalink to &quot;Effective source selection&quot;">​</a></h2><p>Rules:</p><ol><li>If <code>LogRecord.source.source_name</code> is non-empty, use the record-level source</li><li>Otherwise fall back to batch <code>default_source</code></li></ol><h2 id="timeline-aggregation" tabindex="-1">Timeline aggregation <a class="header-anchor" href="#timeline-aggregation" aria-label="Permalink to &quot;Timeline aggregation&quot;">​</a></h2><ul><li>Filter records by <code>trace_id</code></li><li>Group them into lanes by <code>source_fingerprint</code></li><li>Each lane carries: <ul><li><code>event_count</code></li><li><code>error_count</code></li><li><code>first_seen</code></li><li><code>last_seen</code></li><li><code>events[]</code></li></ul></li><li><code>events[]</code> are sorted by timestamp ascending</li><li><code>event_id</code> prefers <code>log_id</code>; otherwise it falls back to <code>source_fingerprint/timestampUnixNano</code></li></ul><h2 id="topology-derivation" tabindex="-1">Topology derivation <a class="header-anchor" href="#topology-derivation" aria-label="Permalink to &quot;Topology derivation&quot;">​</a></h2><ul><li>Sort trace records by timestamp ascending</li><li>Collapse consecutive records with the same <code>source_fingerprint</code> into segments</li><li>Emit edges from adjacent segments</li><li>Repeated edges in the same direction accumulate <code>transition_count</code></li></ul><h2 id="error-counting-rule" tabindex="-1">Error counting rule <a class="header-anchor" href="#error-counting-rule" aria-label="Permalink to &quot;Error counting rule&quot;">​</a></h2><p>The current implementation treats a record as an error when:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>severity_number &gt;= 17</span></span></code></pre></div><p>This affects:</p><ul><li>timeline <code>error_count</code></li><li>topology node <code>error_count</code></li><li>topology edge <code>error_count</code></li></ul><h2 id="source-grouping" tabindex="-1">Source grouping <a class="header-anchor" href="#source-grouping" aria-label="Permalink to &quot;Source grouping&quot;">​</a></h2><p>The source tree is grouped as:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>source_type -&gt; source_name -&gt; instance_id</span></span></code></pre></div><p>If <code>instance_id</code> is empty, the current implementation uses <code>-</code>.</p><h2 id="sources-of-truth" tabindex="-1">Sources of truth <a class="header-anchor" href="#sources-of-truth" aria-label="Permalink to &quot;Sources of truth&quot;">​</a></h2><ul><li><code>internal/ingest/normalize.go</code></li><li><code>internal/store/store.go</code></li><li><code>internal/store/memory/memory.go</code></li></ul>',26)])])}const m=t(a,[["render",i]]);export{h as __pageData,m as default};
